@page "/Account/Login"
@using Microsoft.AspNetCore.Identity
@using sv_950e436475304932896d61f02c58559a.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h3>Login</h3>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }
        <form method="post" @formname="login">
            <AntiforgeryToken />
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" name="email" @bind="email" required />
            </div>
            <div class="mb-3">
                <label class="form-label">Password</label>
                <input type="password" class="form-control" name="password" @bind="password" required />
            </div>
            <input type="hidden" name="returnUrl" value="@returnUrl" />
            <button type="submit" class="btn btn-primary w-100">Log in</button>
        </form>
    </div>
</div>

@code {
    [SupplyParameterFromForm] private string? email { get; set; }
    [SupplyParameterFromForm] private string? password { get; set; }
    [SupplyParameterFromQuery] private string? returnUrl { get; set; }

    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        if (HttpMethods.IsGet(HttpContext.Request.Method))
            return;

        if (string.IsNullOrEmpty(email) || string.IsNullOrEmpty(password))
        {
            errorMessage = "Email and password are required.";
            return;
        }

        var result = await SignInManager.PasswordSignInAsync(email, password, isPersistent: false, lockoutOnFailure: false);
        if (result.Succeeded)
        {
            Navigation.NavigateTo(returnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }

    [CascadingParameter] private HttpContext HttpContext { get; set; } = default!;
}

@page "/Account/Logout"
@using Microsoft.AspNetCore.Identity
@using sv_950e436475304932896d61f02c58559a.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

@code {
    [CascadingParameter] private HttpContext HttpContext { get; set; } = default!;

    protected override async Task OnInitializedAsync()
    {
        if (HttpMethods.IsPost(HttpContext.Request.Method))
        {
            await SignInManager.SignOutAsync();
            Navigation.NavigateTo("/", forceLoad: true);
        }
    }
}

@page "/admin/users"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Identity
@using sv_950e436475304932896d61f02c58559a.Data
@attribute [Authorize(Roles = "Admin")]
@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h3>User Management</h3>

@if (users is null)
{
    <p><em>Loading users...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Display Name</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var (user, roles) in users)
            {
                <tr>
                    <td>@user.Email</td>
                    <td>@user.DisplayName</td>
                    <td>@string.Join(", ", roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<(ApplicationUser User, IList<string> Roles)>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        var result = new List<(ApplicationUser, IList<string>)>();
        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            result.Add((user, roles));
        }
        users = result;
    }
}

